sp_page.css:
/* ======================================================== */
/* FORCE FULL BLEED LAYOUT FOR THIS PAGE ONLY               */
/* ======================================================== */

/* 1. Strip padding from the master containers and page body */
section.page, 
main.body, 
.container-fluid, 
.container {
    padding-left: 0 !important;
    padding-right: 0 !important;
    width: 100% !important;
    max-width: 100% !important;
}

/* 2. Remove all margins and padding from the row wrappers */
.sp-page-row, 
.row {
    margin-left: 0 !important;
    margin-right: 0 !important;
    padding: 0 !important;
    width: 100% !important;
    max-width: 100% !important;
}

/* 3. Kill the 15px Bootstrap gutter padding on the columns */
div[class*="col-"] {
    padding-left: 0 !important;
    padding-right: 0 !important;
}

body .padding-top,
.padding-top {
    padding-top: 0 !important;
}
